export function curriculumFor(id: string): Curriculum {
  return CURRICULA.find(c => c.id === id) ?? CURRICULUM
}

// 학년 문자열 → 기본 과정 id. '고1'·'중2'(매쓰플랫식)와 '중1-1'(과정형) 둘 다 처리
export function defaultCurriculumForGrade(grade: string): string {
  if (grade === '고1') return 'h-cm1'
  if (grade === '고2') return 'h-alg'
  if (grade === '고3') return 'h-calc2'
  const exact = CURRICULA.find(c => c.grade === grade)   // '중1-1'·'초3-2' 과정형
  if (exact) return exact.id
  // 고등 과목명 ('공통수학1'·'대수'·'미적분Ⅰ'·'확률과 통계'·'미적분Ⅱ'·'기하' — 시중교재 grade 형식)
  const byLabel = CURRICULA.find(c => c.label.startsWith(grade))
  if (byLabel) return byLabel.id
  const m = grade.match(/^(초|중)(\d)$/)                  // '중2'·'초5' → 그 학년 1학기
  if (m) {
    const first = CURRICULA.find(c => c.grade === `${m[1]}${m[2]}-1`)
    if (first) return first.id
  }
  return 'm1-1'
}

function eachType(): { t: TypeNode; s: SubUnit; m: MidUnit; u: BigUnit; c: Curriculum }[] {
  const out: { t: TypeNode; s: SubUnit; m: MidUnit; u: BigUnit; c: Curriculum }[] = []
  for (const c of CURRICULA)
    for (const u of c.units)
      for (const m of u.mids)
        for (const s of m.subs)
          for (const t of s.types) out.push({ t, s, m, u, c })
  return out
}

export function allTypeIds(): string[] {
  return eachType().map(x => x.t.id)
}

// 과정 id → 과목 (헤더 과목 스위처 목록 필터용)
export function subjectOfCourse(id?: string): '수학' | '과학' | undefined {
  if (!id) return undefined
  return CURRICULA.find(c => c.id === id)?.subject
}

// 유형 id → 과목. 과학 유형만 트리에 있으므로 과학이면 '과학', 그 외(수학 트리·매쓰플랫 개념id)는 undefined(=수학 취급)
let _typeSubject: Map<string, '수학' | '과학'> | null = null
export function subjectOfType(typeId: string): '수학' | '과학' | undefined {
  if (!_typeSubject) {
    _typeSubject = new Map()
    for (const x of eachType()) _typeSubject.set(x.t.id, x.c.subject ?? '수학')
  }
  return _typeSubject.get(typeId)
}

export function typeName(typeId: string): string {
  return eachType().find(x => x.t.id === typeId)?.t.name ?? typeId
}

// "대단원 · 중단원" (범위 요약용)
export function typeUnitName(typeId: string): string {
  const x = eachType().find(y => y.t.id === typeId)
  return x ? `${x.u.name} · ${x.m.name}` : ''
}

// 유형이 속한 과정의 학년 표기 — 중·초는 '중2-1'식, 고등은 과목명('미적분Ⅰ' 등)
export function courseTagOfType(typeId: string): string {
  const x = eachType().find(y => y.t.id === typeId)
  if (!x) return ''
  const c = x.c
  return c.grade.startsWith('고') ? c.label.replace(' (22개정)', '') : c.grade
}

// 유형이 속한 소단원 id (개념 매칭용)
export function typeSubUnitId(typeId: string): string {
  return eachType().find(x => x.t.id === typeId)?.s.id ?? ''
}
